"""
Parameterized generator for GH1028_statsmodels_8633.

Source PR:    https://github.com/statsmodels/statsmodels/pull/8633
Source Issue: N/A

Seed varies: renames 'about' identifier with suffix across seeds.

Bug: pre-PR state of workspace files contains the bug the PR fixes.
Fix: agent must replicate the PR's changes guided by spec.md.
"""
from __future__ import annotations

import os
from generators.base import TaskGenerator, GeneratedTask


class Generator(TaskGenerator):
    task_id = 'GH1028_statsmodels_8633'
    domain = "Real-World GitHub"
    difficulty = "medium"
    languages = ["python"]

    def generate(self, seed: int) -> GeneratedTask:
        tasks_dir = os.path.join(
            os.path.dirname(__file__), "..", "tasks", 'GH1028_statsmodels_8633'
        )
        with open(os.path.join(tasks_dir, "spec.md")) as f:
            spec_md = f.read()
        with open(os.path.join(tasks_dir, "brief.md")) as f:
            brief_md = f.read()

        files = self._base_workspace()
        # Apply seed-based renaming to prevent direct memorization
        suffixes = ["", "_alt", "_impl"]
        suffix = suffixes[seed % len(suffixes)]
        if suffix:
            for fpath in list(files.keys()):
                files[fpath] = files[fpath].replace('about', 'about' + suffix)
        # Deep parameterization — consistent cross-seed variation
        from generators.gh_deep_param import deep_rename_symbols, add_realistic_noise
        files = deep_rename_symbols(files, seed, strategy="mixed")
        files = add_realistic_noise(files, seed, noise_level=0.15)
        return GeneratedTask(
            task_id='GH1028_statsmodels_8633',
            seed=seed,
            spec_md=spec_md,
            brief_md=brief_md,
            expected={
                "seed": seed,
                "repo": 'statsmodels/statsmodels',
                "pr_number": 8633,
                "bug_fixed": True,
            },
            workspace_files=files,
            metadata={
                "difficulty": "medium",
                "category": "Real-World GitHub",
                "source_pr": "https://github.com/statsmodels/statsmodels/pull/8633",
            },
        )

    def _base_workspace(self) -> dict[str, str]:
        """Return the pre-PR (buggy) workspace files."""
        return {
            'statsmodels/distributions/copula/archimedean.py': '# -*- coding: utf-8 -*-\n"""\nCreated on Fri Jan 29 19:19:45 2021\n\nAuthor: Josef Perktold\nLicense: BSD-3\n\n"""\nimport sys\n\nimport numpy as np\nfrom scipy import stats, integrate, optimize\n\nfrom . import transforms\nfrom .copulas import Copula\nfrom statsmodels.tools.rng_qrng import check_random_state\n\n\ndef _debye(alpha):\n    EPSILON = np.finfo(np.float32).eps\n\n    def integrand(t):\n        return t / (np.exp(t) - 1)\n\n    debye_value = integrate.quad(integrand, EPSILON, alpha)[0] / alpha\n    return debye_value\n\n\nclass ArchimedeanCopula(Copula):\n    """Base class for Archimedean copulas\n\n    Parameters\n    ----------\n    transform : instance of transformation class\n        Archimedean generator with required methods including first and second\n        derivatives\n    args : tuple\n        Optional copula parameters. Copula parameters can be either provided\n        when creating the instance or as arguments when calling methods.\n    k_dim : int\n        Dimension, number of components in the multivariate random variable.\n        Currently only bivariate copulas are verified. Support for more than\n        2 dimension is incomplete.\n    """\n\n    def __init__(self, transform, args=(), k_dim=2):\n        super().__init__(k_dim=k_dim)\n        self.args = args\n        self.transform = transform\n        self.k_args = 1\n\n    def _handle_args(self, args):\n        # TODO: how to we handle non-tuple args? two we allow single values?\n        # Model fit might give an args that can be empty\n        if isinstance(args, np.ndarray):\n            args = tuple(args)  # handles empty arrays, unpacks otherwise\n        if not isinstance(args, tuple):\n            # could still be a scalar or numpy scalar\n            args = (args,)\n        if len(args) == 0 or args == (None,):\n            # second condition because we converted None to tuple\n            args = self.args\n\n        return args\n\n    def cdf(self, u, args=()):\n        """Evaluate cdf of Archimedean copula."""\n        args = self._handle_args(args)\n        axis = -1\n        phi = self.transform.evaluate\n        phi_inv = self.transform.inverse\n        cdfv = phi_inv(phi(u, *args).sum(axis), *args)\n        # clip numerical noise\n        out = cdfv if isinstance(cdfv, np.ndarray) else None\n        cdfv = np.clip(cdfv, 0., 1., out=out)  # inplace if possible\n        return cdfv\n\n    def pdf(self, u, args=()):\n        """Evaluate pdf of Archimedean copula."""\n        args = self._handle_args(args)\n        axis = -1\n        u = np.asarray(u)\n        if u.shape[-1] > 2:\n            msg = "pdf is currently only available for bivariate copula"\n            raise ValueError(msg)\n        # phi = self.transform.evaluate\n        # phi_inv = self.transform.inverse\n        phi_d1 = self.transform.deriv\n        phi_d2 = self.transform.deriv2\n\n        cdfv = self.cdf(u, args=args)\n\n        pdfv = - np.product(phi_d1(u, *args), axis)\n        pdfv *= phi_d2(cdfv, *args)\n        pdfv /= phi_d1(cdfv, *args)**3\n\n        return pdfv\n\n    def logpdf(self, u, args=()):\n        """Evaluate log pdf of multivariate Archimedean copula."""\n        # TODO: replace by formulas, and exp in pdf\n        args = self._handle_args(args)\n        axis = -1\n        u = np.asarray(u)\n        if u.shape[-1] > 2:\n            msg = "pdf is currently only available for bivariate copula"\n            raise ValueError(msg)\n\n        phi_d1 = self.transform.deriv\n        phi_d2 = self.transform.deriv2\n\n        cdfv = self.cdf(u, args=args)\n\n        # I need np.abs because derivatives are negative,\n        # is this correct for mv?\n        logpdfv = np.sum(np.log(np.abs(phi_d1(u, *args))), axis)\n        logpdfv += np.log(np.abs(phi_d2(cdfv, *args) / phi_d1(cdfv, *args)**3))\n\n        return logpdfv\n\n    def _arg_from_tau(self, tau):\n        # for generic compat\n        return self.theta_from_tau(tau)\n\n\nclass ClaytonCopula(ArchimedeanCopula):\n    r"""Clayton copula.\n\n    Dependence is greater in the negative tail than in the positive.\n\n    .. math::\n\n        C_\\theta(u,v) = \\left[ \\max\\left\\{ u^{-\\theta} + v^{-\\theta} -1 ;\n        0 \\right\\} \\right]^{-1/\\theta}\n\n    with :math:`\\theta\\in[-1,\\infty)\\backslash\\{0\\}`.\n\n    """\n\n    def __init__(self, theta=None, k_dim=2):\n        if theta is not None:\n            args = (theta,)\n        else:\n            args = ()\n        super().__init__(transforms.TransfClayton(), args=args, k_dim=k_dim)\n\n        if theta is not None:\n            if theta <= -1 or theta == 0:\n                raise ValueError(\'Theta must be > -1 and !=0\')\n        self.theta = theta\n\n    def rvs(self, nobs=1, args=(), random_state=None):\n        if self.k_dim != 2:\n            msg = "rvs is only available for bivariate copula"\n            raise NotImplementedError(msg)\n        rng = check_random_state(random_state)\n        th, = self._handle_args(args)\n        x = rng.random((nobs, self.k_dim))\n        v = stats.gamma(1. / th).rvs(size=(nobs, 1), random_state=rng)\n        return (1 - np.log(x) / v) ** (-1. / th)\n\n    def pdf(self, u, args=()):\n        u = np.atleast_2d(u)\n        th, = self._handle_args(args)\n        a = (th + 1) * np.prod(u, axis=1) ** -(th + 1)\n        b = np.sum(u ** -th, axis=1) - 1\n        c = -(2 * th + 1) / th\n        return a * b ** c\n\n    def logpdf(self, u, args=()):\n        # we skip Archimedean logpdf, that uses numdiff\n        return super(ArchimedeanCopula, self).logpdf(u, args=args)\n\n    def cdf(self, u, args=()):\n        u = np.atleast_2d(u)\n        th, = self._handle_args(args)\n        return (np.sum(u ** (-th), axis=1) - 1) ** (-1.0 / th)\n\n    def tau(self, theta=None):\n        # Joe 2014 p. 168\n        if theta is None:\n            theta = self.theta\n\n        return theta / (theta + 2)\n\n    def theta_from_tau(self, tau):\n        return 2 * tau / (1 - tau)\n\n\nclass FrankCopula(ArchimedeanCopula):\n    r"""Frank copula.\n\n    Dependence is symmetric.\n\n    .. math::\n\n        C_\\theta(\\mathbf{u}) = -\\frac{1}{\\theta} \\log \\left[ 1-\n        \\frac{ \\prod_j (1-\\exp(- \\theta u_j)) }{ (1 - \\exp(-\\theta)-1)^{d -\n        1} } \\right]\n\n    with :math:`\\theta\\in \\mathbb{R}\\backslash\\{0\\}, \\mathbf{u} \\in [0, 1]^d`.\n\n    """\n\n    def __init__(self, theta=None, k_dim=2):\n        if theta is not None:\n            args = (theta,)\n        else:\n            args = ()\n        super().__init__(transforms.TransfFrank(), args=args, k_dim=k_dim)\n\n        if theta is not None:\n            if theta == 0:\n                raise ValueError(\'Theta must be !=0\')\n        self.theta = theta\n\n    def rvs(self, nobs=1, args=(), random_state=None):\n        if self.k_dim != 2:\n            msg = "rvs is only available for bivariate copula"\n            raise NotImplementedError(msg)\n        rng = check_random_state(random_state)\n        th, = self._handle_args(args)\n        x = rng.random((nobs, self.k_dim))\n        v = stats.logser.rvs(1. - np.exp(-th),\n                             size=(nobs, 1), random_state=rng)\n\n        return -1. / th * np.log(1. + np.exp(-(-np.log(x) / v))\n                                 * (np.exp(-th) - 1.))\n\n    # explicit BV formulas copied from Joe 1997 p. 141\n    # todo: check expm1 and log1p for improved numerical precision\n\n    def pdf(self, u, args=()):\n        u = np.atleast_2d(u)\n        th, = self._handle_args(args)\n        if u.shape[-1] != 2:\n            return super().pdf(u)\n\n        g_ = np.exp(-th * np.sum(u, axis=1)) - 1\n        g1 = np.exp(-th) - 1\n\n        num = -th * g1 * (1 + g_)\n        aux = np.prod(np.exp(-th * u) - 1, axis=1) + g1\n        den = aux ** 2\n        return num / den\n\n    def cdf(self, u, args=()):\n        u = np.atleast_2d(u)\n        th, = self._handle_args(args)\n        dim = u.shape[-1]\n        if dim != 2:\n            return super().cdf(u)\n\n        num = np.prod(1 - np.exp(- th * u), axis=1)\n        den = (1 - np.exp(-th)) ** (dim - 1)\n\n        return -1.0 / th * np.log(1 - num / den)\n\n    def logpdf(self, u, args=()):\n        u = np.atleast_2d(u)\n        th, = self._handle_args(args)\n        if u.shape[-1] == 2:\n            # bivariate case\n            u1, u2 = u[..., 0], u[..., 1]\n            b = 1 - np.exp(-th)\n            pdf = np.log(th * b) - th * (u1 + u2)\n            pdf -= 2 * np.log(b - (1 - np.exp(- th * u1)) *\n                              (1 - np.exp(- th * u2)))\n            return pdf\n        else:\n            # for now use generic from base Copula class, log(self.pdf(...))\n            # we skip Archimedean logpdf, that uses numdiff\n            super(ArchimedeanCopula, self).logpdf(u, args)\n\n    def cdfcond_2g1(self, u, args=()):\n        """Conditional cdf of second component given the value of first.\n        """\n        u = np.atleast_2d(u)\n        th, = self._handle_args(args)\n        if u.shape[-1] == 2:\n            # bivariate case\n            u1, u2 = u[..., 0], u[..., 1]\n            cdfc = np.exp(- th * u1)\n            cdfc /= np.expm1(-th) / np.expm1(- th * u2) + np.expm1(- th * u1)\n            return cdfc\n        else:\n            raise NotImplementedError("u needs to be bivariate (2 columns)")\n\n    def ppfcond_2g1(self, q, u1, args=()):\n        """Conditional pdf of second component given the value of first.\n        """\n        u1 = np.asarray(u1)\n        th, = self._handle_args(args)\n        if u1.shape[-1] == 1:\n            # bivariate case, conditional on value of first variable\n            ppfc = - np.log(1 + np.expm1(- th) /\n                            ((1 / q - 1) * np.exp(-th * u1) + 1)) / th\n\n            return ppfc\n        else:\n            raise NotImplementedError("u needs to be bivariate (2 columns)")\n\n    def tau(self, theta=None):\n        # Joe 2014 p. 166\n        if theta is None:\n            theta = self.theta\n        debye_value = _debye(theta)\n        return 1 + 4 * (debye_value - 1) / theta\n\n    def theta_from_tau(self, tau):\n        MIN_FLOAT_LOG = np.log(sys.float_info.min)\n        MAX_FLOAT_LOG = np.log(sys.float_info.max)\n\n        def _theta_from_tau(alpha):\n            return self.tau(theta=alpha) - tau\n\n        result = optimize.least_squares(_theta_from_tau, 1, bounds=(\n            MIN_FLOAT_LOG, MAX_FLOAT_LOG))\n        theta = result.x[0]\n        return theta\n\n\nclass GumbelCopula(ArchimedeanCopula):\n    r"""Gumbel copula.\n\n    Dependence is greater in the positive tail than in the negative.\n\n    .. math::\n\n        C_\\theta(u,v) = \\exp\\!\\left[ -\\left( (-\\log(u))^\\theta +\n        (-\\log(v))^\\theta \\right)^{1/\\theta} \\right]\n\n    with :math:`\\theta\\in[1,\\infty)`.\n\n    """\n\n    def __init__(self, theta=None, k_dim=2):\n        if theta is not None:\n            args = (theta,)\n        else:\n            args = ()\n        super().__init__(transforms.TransfGumbel(), args=args, k_dim=k_dim)\n\n        if theta is not None:\n            if theta <= 1:\n                raise ValueError(\'Theta must be > 1\')\n        self.theta = theta\n\n    def rvs(self, nobs=1, args=(), random_state=None):\n        if self.k_dim != 2:\n            msg = "rvs is only available for bivariate copula"\n            raise NotImplementedError(msg)\n        rng = check_random_state(random_state)\n        th, = self._handle_args(args)\n        x = rng.random((nobs, self.k_dim))\n        v = stats.levy_stable.rvs(\n            1. / th, 1., 0,\n            np.cos(np.pi / (2 * th)) ** th,\n            size=(nobs, 1), random_state=rng\n        )\n        return np.exp(-(-np.log(x) / v) ** (1. / th))\n\n    def pdf(self, u, args=()):\n        u = np.atleast_2d(u)\n        th, = self._handle_args(args)\n        xy = -np.log(u)\n        xy_theta = xy ** th\n\n        sum_xy_theta = np.sum(xy_theta, axis=1)\n        sum_xy_theta_theta = sum_xy_theta ** (1.0 / th)\n\n        a = np.exp(-sum_xy_theta_theta)\n        b = sum_xy_theta_theta + th - 1.0\n        c = sum_xy_theta ** (1.0 / th - 2)\n        d = np.prod(xy, axis=1) ** (th - 1.0)\n        e = np.prod(u, axis=1) ** (- 1.0)\n\n        return a * b * c * d * e\n\n    def cdf(self, u, args=()):\n        u = np.atleast_2d(u)\n        th, = self._handle_args(args)\n        h = np.sum((-np.log(u)) ** th, axis=1)\n        cdf = np.exp(-h ** (1.0 / th))\n        return cdf\n\n    def logpdf(self, u, args=()):\n        # we skip Archimedean logpdf, that uses numdiff\n        return super(ArchimedeanCopula, self).logpdf(u, args=args)\n\n    def tau(self, theta=None):\n        # Joe 2014 p. 172\n        if theta is None:\n            theta = self.theta\n\n        return (theta - 1) / theta\n\n    def theta_from_tau(self, tau):\n        return 1 / (1 - tau)\n',
            'statsmodels/distributions/copula/copulas.py': '"""\n\nWhich Archimedean is Best?\nExtreme Value copulas formulas are based on Genest 2009\n\nReferences\n----------\n\nGenest, C., 2009. Rank-based inference for bivariate extreme-value\ncopulas. The Annals of Statistics, 37(5), pp.2990-3022.\n\n"""\nfrom abc import ABC, abstractmethod\n\nimport numpy as np\nfrom scipy import stats\n\nfrom statsmodels.graphics import utils\n\n\nclass CopulaDistribution:\n    """Multivariate copula distribution\n\n    Parameters\n    ----------\n    copula : str, instance of copula class\n        String name or instance of a copula class\n    marginals : list of distribution instances\n        Marginal distributions.\n    copargs : tuple\n        Parameters for copula\n\n    Notes\n    -----\n    Status: experimental, argument handling may still change\n\n    """\n    def __init__(self, copula, marginals, cop_args=()):\n\n        self.copula = copula\n\n        # no checking done on marginals\n        self.marginals = marginals\n        self.cop_args = cop_args\n        self.k_vars = len(marginals)\n\n    def rvs(self, nobs=1, cop_args=None, marg_args=None, random_state=None):\n        """Draw `n` in the half-open interval ``[0, 1)``.\n\n        Sample the joint distribution.\n\n        Parameters\n        ----------\n        nobs : int, optional\n            Number of samples to generate in the parameter space.\n            Default is 1.\n        cop_args : tuple\n            Copula parameters. If None, then the copula parameters will be\n            taken from the ``cop_args`` attribute created when initiializing\n            the instance.\n        marg_args : list of tuples\n            Parameters for the marginal distributions. It can be None if none\n            of the marginal distributions have parameters, otherwise it needs\n            to be a list of tuples with the same length has the number of\n            marginal distributions. The list can contain empty tuples for\n            marginal distributions that do not take parameter arguments.\n        random_state : {None, int, `numpy.random.Generator`}, optional\n            If `seed` is None then the legacy singleton NumPy generator.\n            This will change after 0.13 to use a fresh NumPy ``Generator``,\n            so you should explicitly pass a seeded ``Generator`` if you\n            need reproducible results.\n            If `seed` is an int, a new ``Generator`` instance is used,\n            seeded with `seed`.\n            If `seed` is already a ``Generator`` instance then that instance is\n            used.\n\n        Returns\n        -------\n        sample : array_like (n, d)\n            Sample from the joint distribution.\n\n        Notes\n        -----\n        The random samples are generated by creating a sample with uniform\n        margins from the copula, and using ``ppf`` to convert uniform margins\n        to the one specified by the marginal distribution.\n\n        See Also\n        --------\n        statsmodels.tools.rng_qrng.check_random_state\n        """\n        if cop_args is None:\n            cop_args = self.cop_args\n        if marg_args is None:\n            marg_args = [()] * self.k_vars\n\n        sample = self.copula.rvs(nobs=nobs, args=cop_args,\n                                 random_state=random_state)\n\n        for i, dist in enumerate(self.marginals):\n            sample[:, i] = dist.ppf(0.5 + (1 - 1e-10) * (sample[:, i] - 0.5),\n                                    *marg_args[i])\n        return sample\n\n    def cdf(self, y, cop_args=None, marg_args=None):\n        """CDF of copula distribution.\n\n        Parameters\n        ----------\n        y : array_like\n            Values of random variable at which to evaluate cdf.\n            If 2-dimensional, then components of multivariate random variable\n            need to be in columns\n        cop_args : tuple\n            Copula parameters. If None, then the copula parameters will be\n            taken from the ``cop_args`` attribute created when initiializing\n            the instance.\n        marg_args : list of tuples\n            Parameters for the marginal distributions. It can be None if none\n            of the marginal distributions have parameters, otherwise it needs\n            to be a list of tuples with the same length has the number of\n            marginal distributions. The list can contain empty tuples for\n            marginal distributions that do not take parameter arguments.\n\n        Returns\n        -------\n        cdf values\n\n        """\n        y = np.asarray(y)\n        if cop_args is None:\n            cop_args = self.cop_args\n        if marg_args is None:\n            marg_args = [()] * y.shape[-1]\n\n        cdf_marg = []\n        for i in range(self.k_vars):\n            cdf_marg.append(self.marginals[i].cdf(y[..., i], *marg_args[i]))\n\n        u = np.column_stack(cdf_marg)\n        if y.ndim == 1:\n            u = u.squeeze()\n        return self.copula.cdf(u, cop_args)\n\n    def pdf(self, y, cop_args=None, marg_args=None):\n        """PDF of copula distribution.\n\n        Parameters\n        ----------\n        y : array_like\n            Values of random variable at which to evaluate cdf.\n            If 2-dimensional, then components of multivariate random variable\n            need to be in columns\n        cop_args : tuple\n            Copula parameters. If None, then the copula parameters will be\n            taken from the ``cop_args`` attribute created when initiializing\n            the instance.\n        marg_args : list of tuples\n            Parameters for the marginal distributions. It can be None if none\n            of the marginal distributions have parameters, otherwise it needs\n            to be a list of tuples with the same length has the number of\n            marginal distributions. The list can contain empty tuples for\n            marginal distributions that do not take parameter arguments.\n\n        Returns\n        -------\n        pdf values\n        """\n        return np.exp(self.logpdf(y, cop_args=cop_args, marg_args=marg_args))\n\n    def logpdf(self, y, cop_args=None, marg_args=None):\n        """Log-pdf of copula distribution.\n\n        Parameters\n        ----------\n        y : array_like\n            Values of random variable at which to evaluate cdf.\n            If 2-dimensional, then components of multivariate random variable\n            need to be in columns\n        cop_args : tuple\n            Copula parameters. If None, then the copula parameters will be\n            taken from the ``cop_args`` attribute creating when initiializing\n            the instance.\n        marg_args : list of tuples\n            Parameters for the marginal distributions. It can be None if none\n            of the marginal distributions have parameters, otherwise it needs\n            to be a list of tuples with the same length has the number of\n            marginal distributions. The list can contain empty tuples for\n            marginal distributions that do not take parameter arguments.\n\n        Returns\n        -------\n        log-pdf values\n\n        """\n        y = np.asarray(y)\n        if cop_args is None:\n            cop_args = self.cop_args\n        if marg_args is None:\n            marg_args = tuple([()] * y.shape[-1])\n\n        lpdf = 0.0\n        cdf_marg = []\n        for i in range(self.k_vars):\n            lpdf += self.marginals[i].logpdf(y[..., i], *marg_args[i])\n            cdf_marg.append(self.marginals[i].cdf(y[..., i], *marg_args[i]))\n\n        u = np.column_stack(cdf_marg)\n        if y.ndim == 1:\n            u = u.squeeze()\n\n        lpdf += self.copula.logpdf(u, cop_args)\n        return lpdf\n\n\nclass Copula(ABC):\n    r"""A generic Copula class meant for subclassing.\n\n    Notes\n    -----\n    A function :math:`\\phi` on :math:`[0, \\infty]` is the Laplace-Stieltjes\n    transform of a distribution function if and only if :math:`\\phi` is\n    completely monotone and :math:`\\phi(0) = 1` [2]_.\n\n    The following algorithm for sampling a ``d``-dimensional exchangeable\n    Archimedean copula with generator :math:`\\phi` is due to Marshall, Olkin\n    (1988) [1]_, where :math:`LS^{−1}(\\phi)` denotes the inverse\n    Laplace-Stieltjes transform of :math:`\\phi`.\n\n    From a mixture representation with respect to :math:`F`, the following\n    algorithm may be derived for sampling Archimedean copulas, see [1]_.\n\n    1. Sample :math:`V \\sim F = LS^{−1}(\\phi)`.\n    2. Sample i.i.d. :math:`X_i \\sim U[0,1], i \\in \\{1,...,d\\}`.\n    3. Return:math:`(U_1,..., U_d)`, where :math:`U_i = \\phi(−\\log(X_i)/V), i\n       \\in \\{1, ...,d\\}`.\n\n    Detailed properties of each copula can be found in [3]_.\n\n    Instances of the class can access the attributes: ``rng`` for the random\n    number generator (used for the ``seed``).\n\n    **Subclassing**\n\n    When subclassing `Copula` to create a new copula, ``__init__`` and\n    ``random`` must be redefined.\n\n    * ``__init__(theta)``: If the copula\n      does not take advantage of a ``theta``, this parameter can be omitted.\n    * ``random(n, random_state)``: draw ``n`` from the copula.\n    * ``pdf(x)``: PDF from the copula.\n    * ``cdf(x)``: CDF from the copula.\n\n    References\n    ----------\n    .. [1] Marshall AW, Olkin I. “Families of Multivariate Distributions”,\n      Journal of the American Statistical Association, 83, 834–841, 1988.\n    .. [2] Marius Hofert. "Sampling Archimedean copulas",\n      Universität Ulm, 2008.\n    .. rvs[3] Harry Joe. "Dependence Modeling with Copulas", Monographs on\n      Statistics and Applied Probability 134, 2015.\n\n    """\n\n    def __init__(self, k_dim=2):\n        self.k_dim = k_dim\n        if k_dim > 2:\n            import warnings\n            warnings.warn("copulas for more than 2 dimension is untested")\n\n    def rvs(self, nobs=1, args=(), random_state=None):\n        """Draw `n` in the half-open interval ``[0, 1)``.\n\n        Marginals are uniformly distributed.\n\n        Parameters\n        ----------\n        nobs : int, optional\n            Number of samples to generate from the copula. Default is 1.\n        args : tuple\n            Arguments for copula parameters. The number of arguments depends\n            on the copula.\n        random_state : {None, int, `numpy.random.Generator`}, optional\n            If `seed` is None then the legacy singleton NumPy generator.\n            This will change after 0.13 to use a fresh NumPy ``Generator``,\n            so you should explicitly pass a seeded ``Generator`` if you\n            need reproducible results.\n            If `seed` is an int, a new ``Generator`` instance is used,\n            seeded with `seed`.\n            If `seed` is already a ``Generator`` instance then that instance is\n            used.\n\n        Returns\n        -------\n        sample : array_like (nobs, d)\n            Sample from the copula.\n\n        See Also\n        --------\n        statsmodels.tools.rng_qrng.check_random_state\n        """\n        raise NotImplementedError\n\n    @abstractmethod\n    def pdf(self, u, args=()):\n        """Probability density function of copula.\n\n        Parameters\n        ----------\n        u : array_like, 2-D\n            Points of random variables in unit hypercube at which method is\n            evaluated.\n            The second (or last) dimension should be the same as the dimension\n            of the random variable, e.g. 2 for bivariate copula.\n        args : tuple\n            Arguments for copula parameters. The number of arguments depends\n            on the copula.\n\n        Returns\n        -------\n        pdf : ndarray, (nobs, k_dim)\n            Copula pdf evaluated at points ``u``.\n        """\n\n    def logpdf(self, u, args=()):\n        """Log of copula pdf, loglikelihood.\n\n        Parameters\n        ----------\n        u : array_like, 2-D\n            Points of random variables in unit hypercube at which method is\n            evaluated.\n            The second (or last) dimension should be the same as the dimension\n            of the random variable, e.g. 2 for bivariate copula.\n        args : tuple\n            Arguments for copula parameters. The number of arguments depends\n            on the copula.\n\n        Returns\n        -------\n        cdf : ndarray, (nobs, k_dim)\n            Copula log-pdf evaluated at points ``u``.\n        """\n        return np.log(self.pdf(u, *args))\n\n    @abstractmethod\n    def cdf(self, u, args=()):\n        """Cumulative distribution function evaluated at points u.\n\n        Parameters\n        ----------\n        u : array_like, 2-D\n            Points of random variables in unit hypercube at which method is\n            evaluated.\n            The second (or last) dimension should be the same as the dimension\n            of the random variable, e.g. 2 for bivariate copula.\n        args : tuple\n            Arguments for copula parameters. The number of arguments depends\n            on the copula.\n\n        Returns\n        -------\n        cdf : ndarray, (nobs, k_dim)\n            Copula cdf evaluated at points ``u``.\n        """\n\n    def plot_scatter(self, sample=None, nobs=500, random_state=None, ax=None):\n        """Sample the copula and plot.\n\n        Parameters\n        ----------\n        sample : array-like, optional\n            The sample to plot.  If not provided (the default), a sample\n            is generated.\n        nobs : int, optional\n            Number of samples to generate from the copula.\n        random_state : {None, int, `numpy.random.Generator`}, optional\n            If `seed` is None then the legacy singleton NumPy generator.\n            This will change after 0.13 to use a fresh NumPy ``Generator``,\n            so you should explicitly pass a seeded ``Generator`` if you\n            need reproducible results.\n            If `seed` is an int, a new ``Generator`` instance is used,\n            seeded with `seed`.\n            If `seed` is already a ``Generator`` instance then that instance is\n            used.\n        ax : AxesSubplot, optional\n            If given, this subplot is used to plot in instead of a new figure\n            being created.\n\n        Returns\n        -------\n        fig : Figure\n            If `ax` is None, the created figure.  Otherwise the figure to which\n            `ax` is connected.\n        sample : array_like (n, d)\n            Sample from the copula.\n\n        See Also\n        --------\n        statsmodels.tools.rng_qrng.check_random_state\n        """\n        if self.k_dim != 2:\n            raise ValueError("Can only plot 2-dimensional Copula.")\n\n        if sample is None:\n            sample = self.rvs(nobs=nobs, random_state=random_state)\n\n        fig, ax = utils.create_mpl_ax(ax)\n        ax.scatter(sample[:, 0], sample[:, 1])\n        ax.set_xlabel(\'u\')\n        ax.set_ylabel(\'v\')\n\n        return fig, sample\n\n    def plot_pdf(self, ticks_nbr=10, ax=None):\n        """Plot the PDF.\n\n        Parameters\n        ----------\n        ticks_nbr : int, optional\n            Number of color isolines for the PDF. Default is 10.\n        ax : AxesSubplot, optional\n            If given, this subplot is used to plot in instead of a new figure\n            being created.\n\n        Returns\n        -------\n        fig : Figure\n            If `ax` is None, the created figure.  Otherwise the figure to which\n            `ax` is connected.\n\n        """\n        from matplotlib import pyplot as plt\n        if self.k_dim != 2:\n            import warnings\n            warnings.warn("Plotting 2-dimensional Copula.")\n\n        n_samples = 100\n\n        eps = 1e-4\n        uu, vv = np.meshgrid(np.linspace(eps, 1 - eps, n_samples),\n                             np.linspace(eps, 1 - eps, n_samples))\n        points = np.vstack([uu.ravel(), vv.ravel()]).T\n\n        data = self.pdf(points).T.reshape(uu.shape)\n        min_ = np.nanpercentile(data, 5)\n        max_ = np.nanpercentile(data, 95)\n\n        fig, ax = utils.create_mpl_ax(ax)\n\n        vticks = np.linspace(min_, max_, num=ticks_nbr)\n        range_cbar = [min_, max_]\n        cs = ax.contourf(uu, vv, data, vticks,\n                         antialiased=True, vmin=range_cbar[0],\n                         vmax=range_cbar[1])\n\n        ax.set_xlabel("u")\n        ax.set_ylabel("v")\n        ax.set_xlim(0, 1)\n        ax.set_ylim(0, 1)\n        ax.set_aspect(\'equal\')\n        cbar = plt.colorbar(cs, ticks=vticks)\n        cbar.set_label(\'p\')\n        fig.tight_layout()\n\n        return fig\n\n    def tau_simulated(self, nobs=1024, random_state=None):\n        """Kendall\'s tau based on simulated samples.\n\n        Returns\n        -------\n        tau : float\n            Kendall\'s tau.\n\n        """\n        x = self.rvs(nobs, random_state=random_state)\n        return stats.kendalltau(x[:, 0], x[:, 1])[0]\n\n    def fit_corr_param(self, data):\n        """Copula correlation parameter using Kendall\'s tau of sample data.\n\n        Parameters\n        ----------\n        data : array_like\n            Sample data used to fit `theta` using Kendall\'s tau.\n\n        Returns\n        -------\n        corr_param : float\n            Correlation parameter of the copula, ``theta`` in Archimedean and\n            pearson correlation in elliptical.\n        """\n        x = np.asarray(data)\n        if x.shape[1] != 2:\n            import warnings\n            warnings.warn("currently only first pair of data are used"\n                          " to compute kendall\'s tau")\n        tau = stats.kendalltau(x[:, 0], x[:, 1])[0]\n        return self._arg_from_tau(tau)\n\n    def _arg_from_tau(self, tau):\n        """Compute correlation parameter from tau.\n\n        Parameters\n        ----------\n        tau : float\n            Kendall\'s tau.\n\n        Returns\n        -------\n        corr_param : float\n            Correlation parameter of the copula, ``theta`` in Archimedean and\n            pearson correlation in elliptical.\n\n        """\n        raise NotImplementedError\n',
            'statsmodels/distributions/copula/extreme_value.py': '# -*- coding: utf-8 -*-\n""" Extreme Value Copulas\nCreated on Fri Jan 29 19:19:45 2021\n\nAuthor: Josef Perktold\nLicense: BSD-3\n\n"""\n\nimport numpy as np\nfrom .copulas import Copula\n\n\ndef copula_bv_ev(u, transform, args=()):\n    \'\'\'generic bivariate extreme value copula\n    \'\'\'\n    u, v = u\n    return np.exp(np.log(u * v) * (transform(np.log(u)/np.log(u*v), *args)))\n\n\nclass ExtremeValueCopula(Copula):\n    """Extreme value copula constructed from Pickand\'s dependence function.\n\n    Currently only bivariate copulas are available.\n\n    Parameters\n    ----------\n    transform: instance of transformation class\n        Pickand\'s dependence function with required methods including first\n        and second derivatives\n    args : tuple\n        Optional copula parameters. Copula parameters can be either provided\n        when creating the instance or as arguments when calling methods.\n    k_dim : int\n        Currently only bivariate extreme value copulas are supported.\n\n    Notes\n    -----\n    currently the following dependence function and copulas are available\n\n    - AsymLogistic\n    - AsymNegLogistic\n    - AsymMixed\n    - HR\n\n    TEV and AsymBiLogistic currently do not have required derivatives for pdf.\n\n    See Also\n    --------\n    dep_func_ev\n\n    """\n\n    def __init__(self, transform, args=(), k_dim=2):\n        super().__init__(k_dim=k_dim)\n        self.transform = transform\n        self.k_args = transform.k_args\n        self.args = args\n\n    def _handle_args(self, args):\n        # TODO: how to we handle non-tuple args? two we allow single values?\n        # Model fit might give an args that can be empty\n        if isinstance(args, np.ndarray):\n            args = tuple(args)  # handles empty arrays, unpacks otherwise\n        if args == () or args is None:\n            args = self.args\n        if not isinstance(args, tuple):\n            args = (args,)\n\n        return args\n\n    def cdf(self, u, args=()):\n        """Evaluate cdf of bivariate extreme value copula.\n\n        Parameters\n        ----------\n        u : array_like\n            Values of random bivariate random variable, each defined on [0, 1],\n            for which cdf is computed.\n            Can be two dimensional with multivariate components in columns and\n            observation in rows.\n        args : tuple\n            Required parameters for the copula. The meaning and number of\n            parameters in the tuple depends on the specific copula.\n\n        Returns\n        -------\n        CDF values at evaluation points.\n        """\n        # currently only Bivariate\n        u, v = np.asarray(u).T\n        args = self._handle_args(args)\n        cdfv = np.exp(np.log(u * v) *\n                      self.transform(np.log(u)/np.log(u*v), *args))\n        return cdfv\n\n    def pdf(self, u, args=()):\n        """Evaluate pdf of bivariate extreme value copula.\n\n        Parameters\n        ----------\n        u : array_like\n            Values of random bivariate random variable, each defined on [0, 1],\n            for which cdf is computed.\n            Can be two dimensional with multivariate components in columns and\n            observation in rows.\n        args : tuple\n            Required parameters for the copula. The meaning and number of\n            parameters in the tuple depends on the specific copula.\n\n        Returns\n        -------\n        PDF values at evaluation points.\n        """\n        tr = self.transform\n        u1, u2 = np.asarray(u).T\n        args = self._handle_args(args)\n\n        log_u12 = np.log(u1 * u2)\n        t = np.log(u1) / log_u12\n        cdf = self.cdf(u, args)\n        dep = tr(t, *args)\n        d1 = tr.deriv(t, *args)\n        d2 = tr.deriv2(t, *args)\n        pdf_ = cdf / (u1 * u2) * ((dep + (1 - t) * d1) * (dep - t * d1) -\n                                  d2 * (1 - t) * t / log_u12)\n\n        return pdf_\n\n    def logpdf(self, u, args=()):\n        """Evaluate log-pdf of bivariate extreme value copula.\n\n        Parameters\n        ----------\n        u : array_like\n            Values of random bivariate random variable, each defined on [0, 1],\n            for which cdf is computed.\n            Can be two dimensional with multivariate components in columns and\n            observation in rows.\n        args : tuple\n            Required parameters for the copula. The meaning and number of\n            parameters in the tuple depends on the specific copula.\n\n        Returns\n        -------\n        Log-pdf values at evaluation points.\n        """\n        return np.log(self.pdf(u, args=args))\n\n    def conditional_2g1(self, u, args=()):\n        """conditional distribution\n\n        not yet implemented\n\n        C2|1(u2|u1) := ∂C(u1, u2) / ∂u1 = C(u1, u2) / u1 * (A(t) − t A\'(t))\n\n        where t = np.log(v)/np.log(u*v)\n        """\n        raise NotImplementedError\n',
            'statsmodels/distributions/copula/other_copulas.py': '# -*- coding: utf-8 -*-\n"""\nCreated on Fri Jan 29 19:19:45 2021\n\nAuthor: Josef Perktold\nLicense: BSD-3\n\n"""\nimport numpy as np\nfrom scipy import stats\n\nfrom statsmodels.tools.rng_qrng import check_random_state\nfrom statsmodels.distributions.copula.copulas import Copula\n\n\nclass IndependenceCopula(Copula):\n    """Independence copula.\n\n    Copula with independent random variables.\n\n    .. math::\n\n        C_\\theta(u,v) = uv\n\n    Parameters\n    ----------\n    k_dim : int\n        Dimension, number of components in the multivariate random variable.\n\n    Notes\n    -----\n    IndependenceCopula does not have copula parameters.\n    If non-empty ``args`` are provided in methods, then a ValueError is raised.\n    The ``args`` keyword is provided for a consistent interface across\n    copulas.\n\n    """\n    def __init__(self, k_dim=2):\n        super().__init__(k_dim=k_dim)\n\n    def _handle_args(self, args):\n        if args != () and args is not None:\n            msg = ("Independence copula does not use copula parameters.")\n            raise ValueError(msg)\n        else:\n            return args\n\n    def rvs(self, nobs=1, args=(), random_state=None):\n        self._handle_args(args)\n        rng = check_random_state(random_state)\n        x = rng.random((nobs, self.k_dim))\n        return x\n\n    def pdf(self, u, args=()):\n        return np.ones(len(u))\n\n    def cdf(self, u, args=()):\n        return np.prod(u, axis=1)\n\n    def tau(self):\n        return 0\n\n    def plot_pdf(self, *args):\n        raise NotImplementedError("PDF is constant over the domain.")\n\n\ndef rvs_kernel(sample, size, bw=1, k_func=None, return_extras=False):\n    """Random sampling from empirical copula using Beta distribution\n\n    Parameters\n    ----------\n    sample : ndarray\n        Sample of multivariate observations in (o, 1) interval.\n    size : int\n        Number of observations to simulate.\n    bw : float\n        Bandwidth for Beta sampling. The beta copula corresponds to a kernel\n        estimate of the distribution. bw=1 corresponds to the empirical beta\n        copula. A small bandwidth like bw=0.001 corresponds to small noise\n        added to the empirical distribution. Larger bw, e.g. bw=10 corresponds\n        to kernel estimate with more smoothing.\n    k_func : None or callable\n        The default kernel function is currently a beta function with 1 added\n        to the first beta parameter.\n    return_extras : bool\n        If this is False, then only the random sample will be returned.\n        If true, then extra information is returned that is mainly of interest\n        for verification.\n\n    Returns\n    -------\n    rvs : ndarray\n        Multivariate sample with ``size`` observations drawn from the Beta\n        Copula.\n\n    Notes\n    -----\n    Status: experimental, API will change.\n    """\n    # vectorized for observations\n    n = sample.shape[0]\n    if k_func is None:\n        kfunc = _kernel_rvs_beta1\n    idx = np.random.randint(0, n, size=size)\n    xi = sample[idx]\n    krvs = np.column_stack([kfunc(xii, bw) for xii in xi.T])\n\n    if return_extras:\n        return krvs, idx, xi\n    else:\n        return krvs\n\n\ndef _kernel_rvs_beta(x, bw):\n    # Beta kernel for density, pdf, estimation\n    return stats.beta.rvs(x / bw + 1, (1 - x) / bw + 1, size=x.shape)\n\n\ndef _kernel_rvs_beta1(x, bw):\n    # Beta kernel for density, pdf, estimation\n    # Kiriliouk, Segers, Tsukuhara 2020 arxiv, using bandwith 1/nobs sample\n    return stats.beta.rvs(x / bw, (1 - x) / bw + 1)\n',
            'statsmodels/distributions/copula/tests/test_copula.py': '# -*- coding: utf-8 -*-\n"""\nCreated on Thu Jan 14 23:32:57 2021\n\nAuthor: Josef Perktold\nLicense: BSD-3\n\n"""\nfrom statsmodels.compat.pytest import pytest_warns\n\nfrom statsmodels.compat.scipy import SP_LT_15\n\nimport numpy as np\nfrom numpy.testing import assert_allclose, assert_array_almost_equal\nimport pytest\nfrom scipy import stats\n\nfrom statsmodels.distributions.copula.archimedean import (\n    ArchimedeanCopula,\n    ClaytonCopula,\n    FrankCopula,\n    GumbelCopula,\n)\nfrom statsmodels.distributions.copula.copulas import CopulaDistribution\nimport statsmodels.distributions.copula.depfunc_ev as trev\nfrom statsmodels.distributions.copula.elliptical import (\n    GaussianCopula,\n    StudentTCopula,\n)\nfrom statsmodels.distributions.copula.extreme_value import (\n    ExtremeValueCopula,\n    copula_bv_ev,\n)\nfrom statsmodels.distributions.copula.other_copulas import IndependenceCopula\nimport statsmodels.distributions.copula.transforms as tra\nfrom statsmodels.distributions.tools import (\n    approx_copula_pdf,\n    frequencies_fromdata,\n)\nfrom statsmodels.tools.numdiff import approx_fprime_cs, approx_hess\n\nuniform = stats.uniform\n\n\nev_list = [\n    [trev.transform_bilogistic, 0.5, 0.9, (0.25, 0.05), 0.5],\n    [trev.transform_tawn, 0.5, 0.9, (0.5, 0.5, 0.5), 0.4724570876035117],\n    # note evd has asymmetry reversed, interchange variables\n    [trev.transform_tawn2, 0.5, 0.9, (0.25, 0.05), 0.464357480263932],\n    [trev.transform_tawn2, 0.5, 0.9, (0.5, 0.25), 0.4916117128670654],\n    [trev.transform_tawn2, 0.9, 0.5, (0.5, 0.25), 0.48340673415789],\n    # note evd has parameter for hr 1/lmbda (inverse of our parameter)\n    [trev.transform_hr, 0.5, 0.9, (2,), 0.4551235014298542],\n    [trev.transform_joe, 0.5, 0.9, (0.5, 0.75, 1 / 0.25), 0.4543698299835434],\n    [trev.transform_joe, 0.9, 0.5, (0.5, 0.75, 1 / 0.25), 0.4539773435983587],\n    # tev is against R `copula` package\n    # > cop = tevCopula(0.8, df = 4)\n    # > pCopula(c(0.5, 0.75), cop)\n    # [1] 0.456807960674953\n    # > pCopula(c(0.5, 0.9), cop)\n    # [1] 0.4911039761533587\n    [trev.transform_tev, 0.5, 0.75, (0.8, 4), 0.456807960674953],\n    [trev.transform_tev, 0.5, 0.9, (0.8, 4), 0.4911039761533587],\n]\n\nev_dep_list = [\n    # [trev.transform_bilogistic, 0.5, 0.9, (0.25, 0.05), 0.5],\n    [trev.transform_tawn, 0.5, 0.9, (0.5, 0.5, 0.5), 0.4724570876035117,\n     [0.8952847075210475, 0.8535533905932737, 0.8952847075210475]],\n    # abvevd(c(0.25, 0.5, 0.75), dep=0.25, asy = c(0.5, 0.75), model = "alog")\n    [trev.transform_tawn, 0.5, 0.9, (0.5, 0.75, 0.25), 0.4724570876035117,\n     [0.8753426223607659, 0.7672861240893745, 0.8182268471629245]],\n\n    [trev.transform_tawn2, 0.4, 0.9, (0.3, 0.2), 0,\n     [0.8968750000000001, 0.8500000000000000, 0.8781249999999999]],\n    # # note evd has asymmetry reversed, interchange variables - NOT anymore\n    # [trev.transform_tawn2, 0.9, 0.5, (0.25, 0.05), 0.464357480263932],\n    # [trev.transform_tawn2, 0.9, 0.5, (0.5, 0.25), 0.4916117128670654],\n    # [trev.transform_tawn2, 0.5, 0.9, (0.5, 0.25), 0.48340673415789],\n    # # note evd has parameter for hr 1/lmbda (inverse of our parameter)\n    [trev.transform_hr, 0.5, 0.9, (1/2,), 0.4551235014298542,\n     [0.7774638908611127, 0.6914624612740130, 0.7774638908611127]],\n    # [trev.transform_joe, 0.5, 0.9, (0.5, 0.75, 1/0.25), 0.4543698299835434],\n    # [trev.transform_joe, 0.9, 0.5, (0.5, 0.75, 1/0.25), 0.4539773435983587],\n    # > abvevd(c(0.25, 0.5, 0.75), dep=0.75, asy=c(0.5, 0.75), model="aneglog")\n    # [1] 0.9139915932031195 0.8803412942173715 0.8993537417026507\n    [trev.transform_joe, 0.5, 0.9, (0.5, 0.75, 1/0.75), 0.,\n     [0.9139915932031195, 0.8803412942173715, 0.8993537417026507]]\n    ]\n\n\ncop_list = [\n    [tra.TransfFrank, 0.5, 0.9, (2,), 0.4710805107852225, 0.9257812360337806],\n    [tra.TransfGumbel, 0.5, 0.9, (2,), 0.4960348880595387, 0.3973548776136501],\n    [tra.TransfClayton, 0.5, 0.9, (2,), 0.485954322440435, 0.8921974147432954],\n    [tra.TransfIndep, 0.5, 0.5, (), 0.25, 1],\n]\n\ngev_list = [\n    # [cop.transform_tawn, 0.5, 0.9, (0.5, 0.5, 0.5), 0.4724570876035117],\n    # > pbvevd(c(0.5,0.9), dep = 0.25, asy = c(0.5, 0.5), model = "alog")\n    # [trev.transform_tawn, 0.5, 0.9, (0.5, 0.5, 0.25),\n    #  0.4386367545837274, 0.12227570158361],\n    [trev.transform_tawn, 0.5, 0.9, (0.5, 0.75, 0.25),\n     0.4868879662205026, 0.4646154226541540, 0.1897142141905908],\n    [trev.transform_tawn2, 0.4, 0.9, (0.3, 0.2),\n     0.3838690483829361, 0.3989785485000293, 0.1084278364284748],\n    # [trev.transform_tawn2, 0.5, 0.5, (0.5, 0.25), 0.387629940606913,\n    # 0.1383277275273335],\n    # [trev.transform_tawn2, 0.9, 0.5, (0.5, 0.25), 0.4519820720233402,\n    # 0.1162545305128522],  # fails in pdf\n    # note evd has parameter for hr 1/lmbda (inverse of our parameter)\n    [trev.transform_hr, 0.4, 0.9, (2,),\n     0.36459381872178737, 0.34879372499897571, 0.09305880295825367],\n    # [trev.transform_joe, 0.5, 0.9, (0.5, 0.75, 1/0.25), 0.3700584213780548,\n    # 0.08992436735088952],\n    [trev.transform_joe, 0.4, 0.9, (0.5, 0.75, 1/0.25),\n     0.36391125216656162, 0.34752631779552950, 0.09316705199822513],\n    ]\n\n\ndef check_cop_rvs(cop, rvs=None, nobs=2000, k=10, use_pdf=True):\n    if rvs is None:\n        rvs = cop.rvs(nobs)\n    freq = frequencies_fromdata(rvs, k, use_ranks=True)\n    if use_pdf:\n        pdfg = approx_copula_pdf(cop, k_bins=k, force_uniform=True)\n        count_pdf = pdfg * nobs\n    else:\n        # use copula cdf if available\n        raise NotImplementedError\n    mask = count_pdf < 2\n    if mask.sum() > 5:\n        cp = count_pdf[mask]\n        cp = np.concatenate([cp, [nobs - cp.sum()]])\n        fr = freq[mask]\n        cp = np.concatenate([fr, [nobs - fr.sum()]])\n    else:\n        fr = freq.ravel()\n        cp = count_pdf.ravel()\n\n    chi2_test = stats.chisquare(freq.ravel(), count_pdf.ravel())\n    return chi2_test, rvs\n\n\nextrali = [\n    [trev.transform_tawn, 0.5, 0.9, (0.8, 0.5, 0.75), 0.4724570876035117],\n    [trev.transform_tawn, 0.5, 0.9, (0.5, 0.75, 0.5), 0.4724570876035117],\n    [trev.transform_tawn, 0.6, 0.4, (0.2, 0.7, 0.6), 0.4724570876035117],\n]\n\n\n@pytest.mark.parametrize("case", ev_list + extrali)\ndef test_ev_copula(case):\n    # check ev copulas, cdf and transform against R `evd` package\n    ev_tr, v1, v2, args, res1 = case\n    res = copula_bv_ev([v1, v2], ev_tr, args=args)\n    # assert_allclose(res, res1, rtol=1e-13)\n\n    # check derivatives of dependence function\n    if ev_tr in (trev.transform_bilogistic, trev.transform_tev):\n        return\n    d1_res = approx_fprime_cs(np.array([v1, v2]), ev_tr.evaluate, args=args)\n    d1_res = np.diag(d1_res)\n    d1 = ev_tr.deriv(np.array([v1, v2]), *args)\n    assert_allclose(d1, d1_res, rtol=1e-8)\n\n    d1_res = approx_hess(np.array([0.5]), ev_tr.evaluate, args=args)\n    d1_res = np.diag(d1_res)\n    d1 = ev_tr.deriv2(0.5, *args)\n    assert_allclose(d1, d1_res, rtol=1e-7)\n\n\n@pytest.mark.parametrize("case", ev_dep_list)\ndef test_ev_dep(case):\n    ev_tr, v1, v2, args, res1, res2 = case  # noqa\n    t = np.array([0.25, 0.5, 0.75])\n    df = ev_tr(t, *args)\n    assert_allclose(df, res2, rtol=1e-13)\n\n\n@pytest.mark.parametrize("case", cop_list)\ndef test_copulas(case):\n    # check ev copulas, cdf and transform against R `copula` package\n    cop_tr, v1, v2, args, cdf2, pdf2 = case\n    ca = ArchimedeanCopula(cop_tr())\n    cdf1 = ca.cdf([v1, v2], args=args)\n    pdf1 = ca.pdf([v1, v2], args=args)\n    assert_allclose(cdf1, cdf2, rtol=1e-13)\n    assert_allclose(pdf1, pdf2, rtol=1e-13)\n\n    logpdf1 = ca.logpdf([v1, v2], args=args)\n    assert_allclose(logpdf1, np.log(pdf2), rtol=1e-13)\n\n\n@pytest.mark.parametrize("case", ev_list)\ndef test_ev_copula_distr(case):\n    # check ev copulas, cdf and transform against R `evd` package\n    ev_tr, v1, v2, args, res1 = case\n    u = [v1, v2]\n    res = copula_bv_ev(u, ev_tr, args=args)\n    assert_allclose(res, res1, rtol=1e-13)\n\n    ev = ExtremeValueCopula(ev_tr)\n    cdf1 = ev.cdf(u, args)\n    assert_allclose(cdf1, res1, rtol=1e-13)\n\n    cev = CopulaDistribution(ev, [uniform, uniform], cop_args=args)\n    cdfd = cev.cdf(np.array(u), cop_args=args)\n    assert_allclose(cdfd, res1, rtol=1e-13)\n    assert cdfd.shape == ()\n\n    # using list u\n    cdfd = cev.cdf(u, cop_args=args)\n    assert_allclose(cdfd, res1, rtol=1e-13)\n    assert cdfd.shape == ()\n\n    # check vector values for u\n    # bilogistic is not vectorized, uses integrate.quad\n    if ev_tr != trev.transform_bilogistic:\n        cdfd = cev.cdf(np.array(u) * np.ones((3, 1)), cop_args=args)\n        assert_allclose(cdfd, res1, rtol=1e-13)\n        assert cdfd.shape == (3,)\n\n\n@pytest.mark.parametrize("case", cop_list)\ndef test_copulas_distr(case):\n    # check ev copulas, cdf and transform against R `copula` package\n    cop_tr, v1, v2, args, cdf2, pdf2 = case\n    u = [v1, v2]\n    ca = ArchimedeanCopula(cop_tr())\n    cdf1 = ca.cdf(u, args=args)\n    pdf1 = ca.pdf(u, args=args)\n\n    cad = CopulaDistribution(ca, [uniform, uniform], cop_args=args)\n    cdfd = cad.cdf(np.array(u), cop_args=args)\n    assert_allclose(cdfd, cdf1, rtol=1e-13)\n    assert cdfd.shape == ()\n\n    # check pdf\n    pdfd = cad.pdf(np.array(u), cop_args=args)\n    assert_allclose(pdfd, pdf1, rtol=1e-13)\n    assert cdfd.shape == ()\n\n    # using list u\n    cdfd = cad.cdf(u, cop_args=args)\n    assert_allclose(cdfd, cdf1, rtol=1e-13)\n    assert cdfd.shape == ()\n\n    assert_allclose(cdf1, cdf2, rtol=1e-13)\n    assert_allclose(pdf1, pdf2, rtol=1e-13)\n\n    # check vector values for u\n    cdfd = cad.cdf(np.array(u) * np.ones((3, 1)), cop_args=args)\n    assert_allclose(cdfd, cdf2, rtol=1e-13)\n    assert cdfd.shape == (3,)\n\n    # check mv, check at marginal cdf\n    cdfmv = ca.cdf([v1, v2, 1], args=args)\n    assert_allclose(cdfmv, cdf1, rtol=1e-13)\n    assert cdfd.shape == (3,)\n\n\n@pytest.mark.parametrize("case", gev_list)\ndef test_gev_genextreme(case):\n    gev = stats.genextreme(0)\n    # check ev copulas, cdf and transform against R `evt` package\n    ev_tr, v1, v2, args, res0, res1, res2 = case\n    y = [v1, v2]\n    u = gev.cdf(y)\n    res = copula_bv_ev(u, ev_tr, args=args)\n    assert_allclose(res, res1, rtol=1e-13)\n\n    ev = ExtremeValueCopula(ev_tr)\n    # evaluated at using u = y\n    cdf1 = ev.cdf(y, args)\n    assert_allclose(cdf1, res0, rtol=1e-13)\n\n    # evaluated at transformed u = F(y)\n    cdf1 = ev.cdf(u, args)\n    assert_allclose(cdf1, res1, rtol=1e-13)\n\n    cev = CopulaDistribution(ev, [gev, gev], cop_args=args)\n    cdfd = cev.cdf(np.array(y), cop_args=args)\n    assert_allclose(cdfd, res1, rtol=1e-13)\n    pdfd = cev.pdf(np.array(y), cop_args=args)\n    assert_allclose(pdfd, res2, rtol=1e-13)\n\n\nclass TestFrank:\n    def test_basic(self):\n        case = [tra.TransfFrank, 0.5, 0.9, (2,), 0.4710805107852225,\n                0.9257812360337806]\n        cop_tr, v1, v2, args, cdf2, pdf2 = case\n        cop = FrankCopula()\n\n        pdf1 = cop.pdf([v1, v2], args=args)\n        assert_allclose(pdf1, pdf2, rtol=1e-13)\n        logpdf1 = cop.logpdf([v1, v2], args=args)\n        assert_allclose(logpdf1, np.log(pdf2), rtol=1e-13)\n\n        cdf1 = cop.cdf([v1, v2], args=args)\n        assert_allclose(cdf1, cdf2, rtol=1e-13)\n\n        assert isinstance(cop.transform, cop_tr)\n\n        # round trip conditional, no verification\n        u = [0.6, 0.5]\n        cdfc = cop.cdfcond_2g1(u, args=args)\n        ppfc = cop.ppfcond_2g1(cdfc, [0.6], args=args)\n        assert_allclose(ppfc, u[1], rtol=1e-13)\n\n\n# The reference results are coming from the R package Copula.\n# See ``copula_r_tests.rst`` for more details.\n\n\nclass CheckCopula:\n    """Generic tests for copula."""\n\n    copula = None\n    dim = None\n    u = np.array([[0.33706249, 0.6075078],\n                  [0.62232507, 0.06241089],\n                  [0.2001457, 0.54027684],\n                  [0.77166391, 0.40610225],\n                  [0.98534253, 0.99212789],\n                  [0.72755898, 0.25913165],\n                  [0.05943888, 0.61044613],\n                  [0.0962475, 0.67585563],\n                  [0.35496733, 0.79584436],\n                  [0.44513594, 0.23050014]])\n    pdf_u = None\n    cdf_u = None\n\n    def _est_visualization(self):\n        sample = self.copula.rvs(10000)\n        assert sample.shape == (10000, 2)\n        # h = sns.jointplot(sample[:, 0], sample[:, 1], kind=\'hex\')\n        # h.set_axis_labels(\'X1\', \'X2\', fontsize=16)\n\n    def test_pdf(self):\n        pdf_u_test = self.copula.pdf(self.u)\n        assert_array_almost_equal(self.pdf_u, pdf_u_test)\n\n    def test_cdf(self):\n        cdf_u_test = self.copula.cdf(self.u)\n        assert_array_almost_equal(self.cdf_u, cdf_u_test)\n\n    def test_validate_params(self):\n        pass\n\n    def test_rvs(self):\n        nobs = 2000\n        rng = np.random.RandomState(27658622)\n        self.rvs = rvs = self.copula.rvs(nobs, random_state=rng)\n        assert rvs.shape == (nobs, 2)\n        assert_array_almost_equal(\n            np.mean(rvs, axis=0), np.repeat(0.5, self.dim), decimal=2\n        )\n\n        # check empirical quantiles, uniform\n        q0 = np.percentile(rvs, [25, 50, 75], axis=0)\n        q1 = np.repeat(np.array([[0.25, 0.5, 0.75]]).T, 2, axis=1)\n        assert_allclose(q0, q1, atol=0.025)\n\n        tau = stats.kendalltau(*rvs.T)[0]\n        tau_cop = self.copula.tau()\n        assert_allclose(tau, tau_cop, rtol=0.08, atol=0.005)\n\n        if isinstance(self.copula, IndependenceCopula):\n            # skip rest, no `_arg_from_tau` in IndependenceCopula\n            return\n        theta = self.copula.fit_corr_param(rvs)\n        theta_cop = getattr(self.copula, "theta", None)\n        if theta_cop is None:\n            # elliptical\n            theta_cop = self.copula.corr[0, 1]\n        assert_allclose(theta, theta_cop, rtol=0.1, atol=0.005)\n\n\nclass CheckModernCopula(CheckCopula):\n    @pytest.mark.parametrize(\n        "seed", ["random_state", "generator", "qmc", None, 0]\n    )\n    def test_seed(self, seed):\n        if SP_LT_15 and seed in ("generator", 0):\n            pytest.xfail(reason="Generator not supported for SciPy <= 1.3")\n        if seed == "random_state":\n            seed1 = np.random.RandomState(0)\n            seed2 = np.random.RandomState(0)\n        elif seed == "generator":\n            seed1 = np.random.default_rng(0)\n            seed2 = 0\n        elif seed is None:\n            seed1 = None\n            singleton = np.random.mtrand._rand\n            seed2 = np.random.RandomState()\n            seed2.set_state(singleton.get_state())\n        elif seed == "qmc":\n            if not hasattr(stats, "qmc"):\n                pytest.skip("QMC not available")\n            else:\n                pytest.xfail("QMC not working")\n            seed1 = stats.qmc.Halton(2)\n            seed2 = stats.qmc.Halton(2)\n        else:\n            seed1 = 0\n            seed2 = np.random.default_rng(0)\n\n        nobs = 2000\n        expected_warn = None if seed1 is not None else FutureWarning\n        with pytest_warns(expected_warn):\n            rvs1 = self.copula.rvs(nobs, random_state=seed1)\n        rvs2 = self.copula.rvs(nobs, random_state=seed2)\n        assert_allclose(rvs1, rvs2)\n\n\nclass TestIndependenceCopula(CheckCopula):\n    copula = IndependenceCopula()\n    dim = 2\n    pdf_u = np.ones(10)\n    cdf_u = np.prod(CheckCopula.u, axis=1)\n\n\nclass TestGaussianCopula(CheckCopula):\n    copula = GaussianCopula(corr=[[1.0, 0.8], [0.8, 1.0]])\n    dim = 2\n    pdf_u = [1.03308741, 0.06507279, 0.72896012, 0.65389439, 16.45012399,\n             0.34813218, 0.06768115, 0.08168840, 0.40521741, 1.26723470]\n    cdf_u = [0.31906854, 0.06230196, 0.19284669, 0.39952707, 0.98144792,\n             0.25677003, 0.05932818, 0.09605404, 0.35211017, 0.20885480]\n\n    def test_rvs(self):\n        # copied from student t test,\n        # currently inconsistent with non-elliptical copulas\n        super().test_rvs()\n\n        chi2t, rvs = check_cop_rvs(\n            self.copula, rvs=self.rvs, nobs=2000, k=10, use_pdf=True\n        )\n        assert chi2t.pvalue > 0.1\n        tau = stats.kendalltau(*rvs.T)[0]\n        tau_cop = self.copula.tau()\n        assert_allclose(tau, tau_cop, rtol=0.05)\n\n\nclass TestStudentTCopula(CheckCopula):\n    copula = StudentTCopula(corr=[[1.0, 0.8], [0.8, 1.0]], df=2)\n    dim = 2\n    pdf_u = [0.8303065, 0.1359839, 0.5157746, 0.4776421, 26.2173959,\n             0.3070661, 0.1349173, 0.1597064, 0.3303230, 1.0482301]\n    cdf_u = [0.31140349, 0.05942746, 0.18548601, 0.39143974, 0.98347259,\n             0.24894028, 0.05653947, 0.09210693, 0.34447385, 0.20429882]\n\n    def test_cdf(self):\n        pytest.skip("Not implemented.")\n\n    def test_rvs(self):\n        super().test_rvs()\n\n        chi2t, rvs = check_cop_rvs(\n            self.copula, rvs=self.rvs, nobs=2000, k=10, use_pdf=True\n        )\n        assert chi2t.pvalue > 0.1\n        tau = stats.kendalltau(*rvs.T)[0]\n        tau_cop = self.copula.tau()\n        assert_allclose(tau, tau_cop, rtol=0.05)\n\n\nclass TestClaytonCopula(CheckModernCopula):\n    copula = ClaytonCopula(theta=1.2)\n    dim = 2\n    pdf_u = [1.0119836, 0.2072728, 0.8148839, 0.9481976, 2.1419659,\n             0.6828507, 0.2040454, 0.2838497, 0.8197787, 1.1096360]\n    cdf_u = [0.28520375, 0.06101690, 0.17703377, 0.36848218, 0.97772088,\n             0.24082057, 0.05811908, 0.09343934, 0.33012582, 0.18738753]\n\n\nclass TestFrankCopula(CheckModernCopula):\n    copula = FrankCopula(theta=3)\n    dim = 2\n    pdf_u = [0.9646599, 0.5627195, 0.8941964, 0.8364614, 2.9570945,\n             0.6665601, 0.5779906, 0.5241333, 0.7156741, 1.1074024]\n    cdf_u = [0.27467496, 0.05492539, 0.15995939, 0.36750702, 0.97782283,\n             0.23412757, 0.05196265, 0.08676979, 0.32803721, 0.16320730]\n\n\nclass TestGumbelCopula(CheckModernCopula):\n    copula = GumbelCopula(theta=1.5)\n    dim = 2\n    pdf_u = [1.0391696, 0.6539579, 0.9878446, 0.8679504, 16.6030932,\n             0.7542073, 0.6668307, 0.6275887, 0.7477991, 1.1564864]\n    cdf_u = [0.27194634, 0.05484380, 0.15668190, 0.37098420, 0.98176346,\n             0.23422865, 0.05188260, 0.08659615, 0.33086960, 0.15803914]\n',
            'statsmodels/distributions/copula/transforms.py': '# -*- coding: utf-8 -*-\n""" Transformation Classes as generators for Archimedean copulas\n\n\nCreated on Wed Jan 27 14:33:40 2021\n\nAuthor: Josef Perktold\nLicense: BSD-3\n\n"""\nimport warnings\n\nimport numpy as np\nfrom scipy.special import expm1\n\n\n# not used yet\nclass Transforms:\n\n    def __init__(self):\n        pass\n\n\nclass TransfFrank(Transforms):\n\n    def evaluate(self, t, theta):\n        t = np.asarray(t)\n        with warnings.catch_warnings():\n            warnings.simplefilter("ignore", RuntimeWarning)\n            val = -(np.log(-expm1(-theta*t)) - np.log(-expm1(-theta)))\n        return val\n        # return - np.log(expm1(-theta*t) / expm1(-theta))\n\n    def inverse(self, phi, theta):\n        phi = np.asarray(phi)\n        return -np.log1p(np.exp(-phi) * expm1(-theta)) / theta\n\n    def deriv(self, t, theta):\n        t = np.asarray(t)\n        tmp = np.exp(-t*theta)\n        return -theta * tmp/(tmp - 1)\n\n    def deriv2(self, t, theta):\n        t = np.asarray(t)\n        tmp = np.exp(theta * t)\n        d2 = - theta**2 * tmp / (tmp - 1)**2\n        return d2\n\n    def is_completly_monotonic(self, theta):\n        # range of theta for which it is copula for d>2 (more than 2 rvs)\n        return theta > 0 & theta < 1\n\n\nclass TransfClayton(Transforms):\n\n    def _checkargs(self, theta):\n        return theta > 0\n\n    def evaluate(self, t, theta):\n        return np.power(t, -theta) - 1.\n\n    def inverse(self, phi, theta):\n        return np.power(1 + phi, -1/theta)\n\n    def deriv(self, t, theta):\n        return -theta * np.power(t, -theta-1)\n\n    def deriv2(self, t, theta):\n        return theta * (theta + 1) * np.power(t, -theta-2)\n\n    def is_completly_monotonic(self, theta):\n        return theta > 0\n\n\nclass TransfGumbel(Transforms):\n    \'\'\'\n    requires theta >=1\n    \'\'\'\n\n    def _checkargs(self, theta):\n        return theta >= 1\n\n    def evaluate(self, t, theta):\n        return np.power(-np.log(t), theta)\n\n    def inverse(self, phi, theta):\n        return np.exp(-np.power(phi, 1. / theta))\n\n    def deriv(self, t, theta):\n        return - theta * (-np.log(t))**(theta - 1) / t\n\n    def deriv2(self, t, theta):\n        tmp1 = np.log(t)\n        d2 = (theta*(-1)**(1 + theta) * tmp1**(theta-1) * (1 - theta) +\n              theta*(-1)**(1 + theta)*tmp1**theta)/(t**2*tmp1)\n        # d2 = (theta * tmp1**(-1 + theta) * (1 - theta) + theta * tmp1**theta\n        #       ) / (t**2 * tmp1)\n\n        return d2\n\n    def is_completly_monotonic(self, theta):\n        return theta > 1\n\n\nclass TransfIndep(Transforms):\n\n    def evaluate(self, t, *args):\n        t = np.asarray(t)\n        return -np.log(t)\n\n    def inverse(self, phi, *args):\n        phi = np.asarray(phi)\n        return np.exp(-phi)\n\n    def deriv(self, t, *args):\n        t = np.asarray(t)\n        return - 1./t\n\n    def deriv2(self, t, *args):\n        t = np.asarray(t)\n        return 1. / t**2\n\n\nclass _TransfPower(Transforms):\n    """generic multivariate Archimedean copula with additional power transforms\n\n    Nelson p.144, equ. 4.5.2\n\n    experimental, not yet tested and used\n    """\n\n    def __init__(self, transform):\n        self.transform = transform\n\n    def evaluate(self, t, alpha, beta, *tr_args):\n        t = np.asarray(t)\n\n        phi = np.power(self.transform.evaluate(np.power(t, alpha), *tr_args),\n                       beta)\n        return phi\n\n    def inverse(self, phi, alpha, beta, *tr_args):\n        phi = np.asarray(phi)\n        transf = self.transform\n        phi_inv = np.power(transf.evaluate(np.power(phi, 1. / beta), *tr_args),\n                           1. / alpha)\n        return phi_inv\n',
        }
